import{_ as a,o as r,c as s,ak as t}from"./chunks/framework.Bj6Oe1e0.js";const h=JSON.parse('{"title":"Base","description":"","frontmatter":{},"headers":[],"relativePath":"AUTOSAR 实践/MCAL 模块详解/Base.md","filePath":"AUTOSAR 实践/MCAL 模块详解/Base.md"}'),o={name:"AUTOSAR 实践/MCAL 模块详解/Base.md"};function i(n,e,l,c,f,p){return r(),s("div",null,[...e[0]||(e[0]=[t('<h1 id="base" tabindex="-1">Base <a class="header-anchor" href="#base" aria-label="Permalink to “Base”">​</a></h1><p>Base 模块包含了一系列 Mcal 配置所需要的参数，包括对 OsIf （Operating System Interface）的配置等。所有的 Mcal 模块都需要依赖 Base。</p><h2 id="general" tabindex="-1">General <a class="header-anchor" href="#general" aria-label="Permalink to “General”">​</a></h2><p>General 中包含了一系列开关（复选框），对应着一系列宏定义是否被定义（define）。下面进行说明。</p><h3 id="osifmulticoresupport" tabindex="-1">OsIfMulticoreSupport <a class="header-anchor" href="#osifmulticoresupport" aria-label="Permalink to “OsIfMulticoreSupport”">​</a></h3><p>控制 OsIf 是否支持多核。如果开启，需要对各外设的 PartitionRef 进行设置。</p><blockquote><p>目前车队所用的芯片暂时不需要这项功能。</p></blockquote><h3 id="osifenableusermodesupport" tabindex="-1">OsIfEnableUserModeSupport <a class="header-anchor" href="#osifenableusermodesupport" aria-label="Permalink to “OsIfEnableUserModeSupport”">​</a></h3><p>控制 OsIf 是否支持 User Mode。如果开启，需要手动编写相关代码。</p><blockquote><p>User Mode 是 AUTOSAR标准包含的一套针对处理器访问权限（尤其是特权级别）的安全机制，依托操作系统配置与硬件 MPU 支持，用于增强任务隔离与系统安全性。</p></blockquote><h3 id="osifdeverrordetect" tabindex="-1">OsIfDevErrorDetect <a class="header-anchor" href="#osifdeverrordetect" aria-label="Permalink to “OsIfDevErrorDetect”">​</a></h3><p>是否启用错误检测 (development error detection and notification)，需要启用 Det 模块。</p><h3 id="osifusesystemtimer" tabindex="-1">OsIfUseSystemTimer <a class="header-anchor" href="#osifusesystemtimer" aria-label="Permalink to “OsIfUseSystemTimer”">​</a></h3><p>是否使用系统定时器。</p><h3 id="osifusecustomtimer" tabindex="-1">OsIfUseCustomTimer <a class="header-anchor" href="#osifusecustomtimer" aria-label="Permalink to “OsIfUseCustomTimer”">​</a></h3><p>是否启用自定义定时器。启用后 Mcal 不再自动提供定时器源，需要手动实现一个返回当前时间戳的函数。</p><h3 id="osifinstanceid" tabindex="-1">OsIfInstanceId <a class="header-anchor" href="#osifinstanceid" aria-label="Permalink to “OsIfInstanceId”">​</a></h3><p>在启用 Custom Timer 时，其不具有意义。如果默认使用 Gpt 等时，决定使用哪个定时器实例。</p><h3 id="osifoperatingsystemtype" tabindex="-1">OsIfOperatingSystemType <a class="header-anchor" href="#osifoperatingsystemtype" aria-label="Permalink to “OsIfOperatingSystemType”">​</a></h3><p>选择 Os Interface 类型，包括使用AutosarOS、FreeRTOS、Baramental。</p><h2 id="osifcounterconfig" tabindex="-1">OsIfCounterConfig <a class="header-anchor" href="#osifcounterconfig" aria-label="Permalink to “OsIfCounterConfig”">​</a></h2><p>是 OsIf 模块内部用于初始化并使用硬件定时器的配置结构体。</p><h3 id="osifsystemtimerclockref" tabindex="-1">OsIfSystemTimerClockRef <a class="header-anchor" href="#osifsystemtimerclockref" aria-label="Permalink to “OsIfSystemTimerClockRef”">​</a></h3><p>系统时钟源参考。</p><p>这个时钟源驱动 CPU 上的应用运行。</p><p>该选项在 Mcu 中被配置，详见 [[Mcu]]。</p>',26)])])}const m=a(o,[["render",i]]);export{h as __pageData,m as default};
